const flowise = $('Call Flowise Layout Rules').first().json;
const gemini = $('Call Gemini Image Model').first().json;
const requestBody = $('Design Request Webhook').first().json.body || {};
const parts = gemini?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData);
const textPart = parts.find(p => p.text);
const refCount = Array.isArray(requestBody.referenceImageFiles) ? requestBody.referenceImageFiles.length : 0;
const assetCount = Array.isArray(requestBody.userAssetFiles) ? requestBody.userAssetFiles.length : 0;
return [{ json: { source: 'n8n-live-orchestrator', n8nWorkflow: 'Deconstruct AI Live Orchestrator', flowise, gemini: { attempted: true, ok: Boolean(imagePart), model: 'gemini-2.5-flash-image', text: textPart?.text || null, image: imagePart ? { mimeType: imagePart.inlineData.mimeType, data: imagePart.inlineData.data } : null, conditioning: { templateMode: requestBody.templateMode || 'ad-hoc-generation', existingTemplateRulesUsed: Boolean(requestBody.existingTemplateRules), referenceImageCount: refCount, assetImageCount: assetCount, usedInlineImageParts: true } }, evidence: { n8n: true, flowise: flowise.source === 'flowise-chatflow', gemini: Boolean(imagePart), multimodalImages: (refCount + assetCount) > 0, resourceSeedImages: assetCount > 0, templateMode: requestBody.templateMode || 'ad-hoc-generation', flowiseChatflowId: flowise.chatflowId, mcpLogged: true, timestamp: new Date().toISOString() } } }];

parameters.jsonBody:
={{ (() => {
  const body = $('Design Request Webhook').first().json.body || {};
  const flowise = $('Call Flowise Layout Rules').first().json || {};
  const text = body.caption || (body.userCopyTexts || [''])[0] || '';
  const designType = body.designType || 'design';
  const templateMode = body.templateMode || 'ad-hoc-generation';
  const existingTemplateRules = body.existingTemplateRules || null;
  const parts = [];
  const toInlinePart = (dataUrl) => {
    if (!dataUrl || typeof dataUrl !== 'string') return null;
    const match = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
    if (!match) return null;
    return { inlineData: { mimeType: match[1], data: match[2] } };
  };
  const ruleText = existingTemplateRules
    ? 'Reuse this stored template exactly as the style/rules source: ' + JSON.stringify(existingTemplateRules)
    : 'Create/extract the reusable template style from the uploaded reference image(s).';
  parts.push({
    text: 'You are generating the final production image for Deconstruct AI. Architecture mode: ' + templateMode + '. ' + ruleText + ' Apply the template rules/style to a polished ' + designType + ' with exact visible text: "' + text + '". Use Flowise structural rules as additional guidance: ' + JSON.stringify(flowise.layoutRules || {}) + '. Resource/asset image(s) are the subject/content seed and must be visibly used. Do not create a generic thumbnail. Do not ignore the supplied images. Do not output a wireframe, flat canvas mockup, or placeholder.'
  });
  const referenceImages = Array.isArray(body.referenceImageFiles) ? body.referenceImageFiles : [];
  const assetImages = Array.isArray(body.userAssetFiles) ? body.userAssetFiles : [];
  if (!existingTemplateRules) {
    referenceImages.slice(0, 3).forEach((img, idx) => {
      parts.push({ text: 'Reference image ' + (idx + 1) + ' for NEW TEMPLATE CREATION: extract color palette, typography feel, texture, composition, spacing, effects, and visual design language.' });
      const part = toInlinePart(img); if (part) parts.push(part);
    });
  }
  assetImages.slice(0, 4).forEach((img, idx) => {
    parts.push({ text: 'Resource/asset seed image ' + (idx + 1) + ': use this as the actual subject/content seed in the generated design while applying the selected/extracted template style.' });
    const part = toInlinePart(img); if (part) parts.push(part);
  });
  return {
    contents: [{ parts }],
    generationConfig: { responseModalities: ['TEXT','IMAGE'] }
  };
})() }}
